// InputValidator.java - Centralized input validation
package com.b2b.order;

import java.util.List;
import java.util.regex.Pattern;

public final class InputValidator {

    private static final Pattern ORDER_ID_PATTERN = Pattern.compile("^ORD-[A-Z0-9]{1,20}$");
    private static final Pattern CUSTOMER_ID_PATTERN = Pattern.compile("^CUST-[A-Z0-9]{1,20}$");
    private static final Pattern ITEM_ID_PATTERN = Pattern.compile("^ITEM-[0-9]{3}$");
    private static final int MAX_ITEMS_PER_ORDER = 100;
    private static final int MAX_QUANTITY_PER_ITEM = 10000;
    private static final int MIN_QUANTITY_PER_ITEM = 1;

    private InputValidator() {}

    public static void validateOrderRequest(OrderRequest request) throws OrderValidationException {
        if (request == null) {
            throw new OrderValidationException("Order request must not be null.");
        }

        validateOrderId(request.getOrderId());
        validateCustomerId(request.getCustomerId());
        validateItems(request.getItems());
    }

    private static void validateOrderId(String orderId) throws OrderValidationException {
        if (orderId == null || orderId.trim().isEmpty()) {
            throw new OrderValidationException("Order ID is required.");
        }
        if (!ORDER_ID_PATTERN.matcher(orderId).matches()) {
            throw new OrderValidationException("Order ID format is invalid. Expected format: ORD-[A-Z0-9]{1,20}");
        }
    }

    private static void validateCustomerId(String customerId) throws OrderValidationException {
        if (customerId == null || customerId.trim().isEmpty()) {
            throw new OrderValidationException("Customer ID is required.");
        }
        if (!CUSTOMER_ID_PATTERN.matcher(customerId).matches()) {
            throw new OrderValidationException("Customer ID format is invalid. Expected format: CUST-[A-Z0-9]{1,20}");
        }
    }

    private static void validateItems(List<OrderItem> items) throws OrderValidationException {
        if (items == null || items.isEmpty()) {
            throw new OrderValidationException("Order must contain at least one item.");
        }
        if (items.size() > MAX_ITEMS_PER_ORDER) {
            throw new OrderValidationException("Order cannot contain more than " + MAX_ITEMS_PER_ORDER + " items.");
        }

        for (OrderItem item : items) {
            validateItem(item);
        }
    }

    private static void validateItem(OrderItem item) throws OrderValidationException {
        if (item == null) {
            throw new OrderValidationException("Order item must not be null.");
        }
        if (item.getItemId() == null || item.getItemId().trim().isEmpty()) {
            throw new OrderValidationException("Item ID is required for each order item.");
        }
        if (!ITEM_ID_PATTERN.matcher(item.getItemId()).matches()) {
            throw new OrderValidationException("Item ID format is invalid: " + sanitize(item.getItemId()));
        }
        if (!ProductCatalog.exists(item.getItemId())) {
            throw new OrderValidationException("Item not found in catalog: " + sanitize(item.getItemId()));
        }
        if (item.getQuantity() < MIN_QUANTITY_PER_ITEM) {
            throw new OrderValidationException("Quantity must be at least " + MIN_QUANTITY_PER_ITEM + " for item: " + sanitize(item.getItemId()));
        }
        if (item.getQuantity() > MAX_QUANTITY_PER_ITEM) {
            throw new OrderValidationException("Quantity cannot exceed " + MAX_QUANTITY_PER_ITEM + " for item: " + sanitize(item.getItemId()));
        }

        ProductCatalog.ProductInfo product = ProductCatalog.getProduct(item.getItemId());
        if (item.getQuantity() > product.getAvailableStock()) {
            throw new OrderValidationException("Insufficient stock for item: " + sanitize(item.getItemId())
                    + ". Requested: " + item.getQuantity() + ", Available: " + product.getAvailableStock());
        }
    }

    private static String sanitize(String input) {
        if (input == null) return "null";
        return input.replaceAll("[^A-Za-z0-9\\-]", "");
    }
}

