package com.b2b.order;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.util.Collections;
import java.util.Iterator;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

public class SOAPMessageValidator implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(SOAPMessageValidator.class.getName());
    private static final String TARGET_NAMESPACE = "http://b2b.com/order";
    private static final int MAX_SOAP_MESSAGE_DEPTH = 10;
    private static final int MAX_SOAP_ELEMENTS = 500;

    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.TRUE.equals(isOutbound)) {
            return true;
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPBody body = envelope.getBody();

            // Check for XML bomb / entity expansion attacks by limiting depth and element count
            validateMessageStructure(body);

            // Reject messages with unexpected SOAP headers that could indicate tampering
            validateHeaders(envelope);

            // Ensure no DTD processing (XXE prevention at SOAP level)
            // Note: JAX-WS should be configured to disable DTD processing at the parser level

            LOGGER.fine("SOAP message validation passed.");
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.WARNING, "SOAP message validation failed: " + e.getMessage());
            throw new javax.xml.ws.soap.SOAPFaultException(
                createSOAPFault("SOAP message validation failed.")
            );
        } catch (SecurityException e) {
            LOGGER.log(Level.WARNING, "SOAP security validation failed: " + e.getMessage());
            throw new javax.xml.ws.soap.SOAPFaultException(
                createSOAPFault("SOAP security validation failed.")
            );
        }
    }

    private void validateMessageStructure(SOAPBody body) {
        int[] counts = {0};
        checkDepthAndCount(body, 0, counts);
    }

    private void checkDepthAndCount(Node node, int depth, int[] elementCount) {
        if (depth > MAX_SOAP_MESSAGE_DEPTH) {
            throw new SecurityException("SOAP message exceeds maximum allowed depth.");
        }
        elementCount[0]++;
        if (elementCount[0] > MAX_SOAP_ELEMENTS) {
            throw new SecurityException("SOAP message exceeds maximum allowed element count.");
        }
        NodeList children = node.getChildNodes();
        if (children != null) {
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                    checkDepthAndCount(children.item(i), depth + 1, elementCount);
                }
            }
        }
    }

    private void validateHeaders(SOAPEnvelope envelope) throws SOAPException {
        SOAPHeader header = envelope.getHeader();
        if (header != null) {
            Iterator<?> headerElements = header.examineAllHeaderElements();
            while (headerElements.hasNext()) {
                javax.xml.soap.SOAPHeaderElement headerElement =
                    (javax.xml.soap.SOAPHeaderElement) headerElements.next();
                String namespaceURI = headerElement.getNamespaceURI();
                // Only allow known namespaces
                if (namespaceURI != null && !namespaceURI.equals(TARGET_NAMESPACE)
                        && !namespaceURI.startsWith("http://schemas.xmlsoap.org/")
                        && !namespaceURI.startsWith("http://www.w3.org/")) {
                    LOGGER.warning("Unexpected SOAP header namespace detected: " + namespaceURI);
                    throw new SecurityException("Unexpected SOAP header detected.");
                }
            }
        }
    }

    private javax.xml.soap.SOAPFault createSOAPFault(String message) {
        try {
            javax.xml.soap.SOAPFactory factory = javax.xml.soap.SOAPFactory.newInstance();
            return factory.createFault(message, new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to create SOAP fault", e);
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No cleanup needed
    }
}

// AuthenticationHandler.java - WS-Security authentication handler
package com.b2b.order;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.util.Collections;
import java.util.Iterator;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

public class AuthenticationHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(AuthenticationHandler.class.getName());
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    @Override
    public Set<QName> getHeaders() {
        return Collections.singleton(new QName(WSSE_NS, "Security"));
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.TRUE.equals(isOutbound)) {
            return true;
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                LOGGER.warning("Missing SOAP security header.");
                throw new SecurityException("Authentication required: Missing security header.");
            }

            // Extract WS-Security UsernameToken
            String username = null;
            String apiKey = null;

            Iterator<?> securityHeaders = header.getChildElements(new QName(WSSE_NS, "Security"));
            if (securityHeaders.hasNext()) {
                Node securityNode = (Node) securityHeaders.next();
                NodeList children = securityNode.getChildNodes();
                for (int i = 0; i < children.getLength(); i++) {
                    Node child = children.item(i);
                    if ("UsernameToken".equals(child.getLocalName())) {
                        NodeList tokenChildren = child.getChildNodes();
                        for (int j = 0; j < tokenChildren.getLength(); j++) {
                            Node tokenChild = tokenChildren.item(j);
                            if ("Username".equals(tokenChild.getLocalName())) {
                                username = tokenChild.getTextContent();
                            } else if ("Password".equals(tokenChild.getLocalName())) {
                                apiKey = tokenChild.getTextContent();
                            }
                        }
                    }
                }
            }

            if (username == null || apiKey == null) {
                LOGGER.warning("Missing authentication credentials in SOAP header.");
                throw new SecurityException("Authentication required: Missing credentials.");
            }

            // Validate credentials (in production, use a secure credential store)
            if (!authenticateClient(username, apiKey)) {
                LOGGER.warning("Authentication failed for user: " + sanitize(username));
                throw new SecurityException("Authentication failed: Invalid credentials.");
            }

            // Store authenticated principal in message context
            context.put("authenticated.user", username);
            context.setScope("authenticated.user", MessageContext.Scope.APPLICATION);

            LOGGER.info("Authenticated B2B client: " + sanitize(username));
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.WARNING, "SOAP authentication processing error", e);
            throw new javax.xml.ws.soap.SOAPFaultException(
                createSOAPFault("Authentication processing error.")
            );
        } catch (SecurityException e) {
            throw new javax.xml.ws.soap.SOAPFaultException(
                createSOAPFault(e.getMessage())
            );
        }
    }

    private boolean authenticateClient(String username, String apiKey) {
        // In production: validate against secure credential store with hashed keys
        // This is a placeholder for demonstration
        // Use constant-time comparison to prevent timing attacks
        return constantTimeEquals("b2b-partner-1", username)
            && constantTimeEquals("secure-api-key-hash-here", apiKey);
    }

    private boolean constantTimeEquals(String a, String b) {
        if (a == null || b == null) return false;
        if (a.length() != b.length()) return false;
        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }

    private String sanitize(String input) {
        if (input == null) return "null";
        return input.replaceAll("[^A-Za-z0-9\\-]", "").substring(0, Math.min(input.length(), 50));
    }

    private javax.xml.soap.SOAPFault createSOAPFault(String message) {
        try {
            javax.xml.soap.SOAPFactory factory = javax.xml.soap.SOAPFactory.newInstance();
            return factory.createFault(message, new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to create SOAP fault", e);
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No cleanup needed
    }
}

