// OrderProcessingServiceImpl.java - Main service implementation
package com.b2b.order;

import javax.annotation.Resource;
import javax.jws.HandlerChain;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "OrderProcessingService",
    portName = "OrderProcessingPort",
    endpointInterface = "com.b2b.order.OrderProcessingService",
    targetNamespace = "http://b2b.com/order",
    wsdlLocation = "WEB-INF/wsdl/OrderProcessingService.wsdl"
)
@HandlerChain(file = "handler-chain.xml")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    private static final Logger LOGGER = Logger.getLogger(OrderProcessingServiceImpl.class.getName());

    // In production, use a database
    private static final Map<String, OrderResponse> ORDER_STORE = new ConcurrentHashMap<>();

    @Resource
    private WebServiceContext webServiceContext;

    @Override
    public OrderResponse processOrder(OrderRequest orderRequest) throws OrderProcessingException {
        LOGGER.info("Received order processing request.");

        // Step 1: Validate all input parameters strictly
        try {
            InputValidator.validateOrderRequest(orderRequest);
        } catch (OrderValidationException e) {
            LOGGER.warning("Order validation failed: " + e.getMessage());
            throw new OrderProcessingException(
                "Validation failed",
                new OrderProcessingFault("VALIDATION_ERROR", e.getMessage())
            );
        }

        // Step 2: Check for duplicate order (idempotency)
        if (ORDER_STORE.containsKey(orderRequest.getOrderId())) {
            LOGGER.info("Duplicate order detected: " + orderRequest.getOrderId());
            return ORDER_STORE.get(orderRequest.getOrderId());
        }

        // Step 3: Calculate total price using SERVER-SIDE authoritative prices only
        // SECURITY: Never trust client-supplied prices. Always look up prices from
        // the server-side product catalog. This prevents SOAP parameter tampering
        // where an attacker modifies price values in the SOAP body.
        BigDecimal totalPrice = BigDecimal.ZERO;

        for (OrderItem item : orderRequest.getItems()) {
            ProductCatalog.ProductInfo product = ProductCatalog.getProduct(item.getItemId());

            if (product == null) {
                // This should not happen after validation, but defense in depth
                throw new OrderProcessingException(
                    "Product not found",
                    new OrderProcessingFault("PRODUCT_NOT_FOUND",
                        "Product not found: " + item.getItemId())
                );
            }

            // Use server-side price exclusively - ignore any price from the client
            BigDecimal serverPrice = product.getPrice();
            BigDecimal itemTotal = serverPrice.multiply(BigDecimal.valueOf(item.getQuantity()));

            // Check for overflow
            if (itemTotal.compareTo(new BigDecimal("999999999.99")) > 0) {
                throw new OrderProcessingException(
                    "Order total exceeded",
                    new OrderProcessingFault("LIMIT_EXCEEDED",
                        "Item total exceeds maximum allowed value for item: " + item.getItemId())
                );
            }

            totalPrice = totalPrice.add(itemTotal);

            // Log the server-side price used (for audit trail)
            LOGGER.info(String.format("Item %s: qty=%d, server_price=%s, item_total=%s",
                item.getItemId(), item.getQuantity(), serverPrice, itemTotal));
        }

        // Final total validation
        totalPrice = totalPrice.setScale(2, RoundingMode.HALF_UP);
        if (totalPrice.compareTo(new BigDecimal("9999999.99")) > 0) {
            throw new OrderProcessingException(
                "Order total exceeded",
                new OrderProcessingFault("LIMIT_EXCEEDED",
                    "Order total exceeds maximum allowed value.")
            );
        }

        if (totalPrice.compareTo(BigDecimal.ZERO) <= 0) {
            throw new OrderProcessingException(
                "Invalid total",
                new OrderProcessingFault("INVALID_TOTAL",
                    "Calculated order total is invalid.")
            );
        }

        // Step 4: Build response
        OrderResponse response = new OrderResponse();
        response.setOrderId(orderRequest.getOrderId());
        response.setStatus("CONFIRMED");
        response.setTotalPrice(totalPrice);
        response.setMessage("Order processed successfully. Total calculated from server-side catalog prices.");

        // Step 5: Store order (idempotency support)
        ORDER_STORE.put(orderRequest.getOrderId(), response);

        // Step 6: Audit log
        String authenticatedUser = getAuthenticatedUser();
        LOGGER.info(String.format("Order %s processed for customer %s by authenticated user %s. Total: %s",
            orderRequest.getOrderId(), orderRequest.getCustomerId(),
            authenticatedUser != null ? authenticatedUser : "unknown",
            totalPrice));

        return response;
    }

    @Override
    public OrderResponse getOrderStatus(String orderId) throws OrderProcessingException {
        // Validate orderId format
        if (orderId == null || !orderId.matches("^ORD-[A-Z0-9]{1,20}$")) {
            throw new OrderProcessingException(
                "Invalid order ID",
                new OrderProcessingFault("VALIDATION_ERROR", "Invalid order ID format.")
            );
        }

        OrderResponse response = ORDER_STORE.get(orderId);
        if (response == null) {
            throw new OrderProcessingException(
                "Order not found",
                new OrderProcessingFault("NOT_FOUND", "Order not found: " + orderId)
            );
        }

        return response;
    }

    private String getAuthenticatedUser() {
        if (webServiceContext != null) {
            MessageContext msgContext = webServiceContext.getMessageContext();
            if (msgContext != null) {
                Object user = msgContext.get("authenticated.user");
                return user != null ? user.toString() : null;
            }
        }
        return null;
    }
}

// OrderServicePublisher.java - For standalone testing
package com.b2b.order;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class OrderServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(OrderServicePublisher.class.getName());

    public static void main(String[] args) {
        String address = "http://localhost:8080/b2b/OrderProcessingService";

        Endpoint endpoint = Endpoint.create(new OrderProcessingServiceImpl());

        // Set handler resolver for security handlers
        endpoint.getBinding().getHandlerChain().add(new SOAPMessageValidator());
        endpoint.getBinding().getHandlerChain().add(new AuthenticationHandler());

        endpoint.publish(address);

        LOGGER.info("B2B Order Processing Service published at: " + address);
        LOGGER.info("WSDL available at: " + address + "?wsdl");
        LOGGER.info("Security: Server-side price lookup enabled. Client-supplied prices are ignored.");
        LOGGER.info("Security: SOAP message validation and authentication handlers active.");
    }
}